custom_css:
/* Verdant - Custom CSS */

/* Preserve Font Awesome icons */
.fa, .fas, .far, .fal, .fab, .fa-solid, .fa-regular, .fa-light, .fa-brands,
[class^="fa-"], [class*=" fa-"] {
  font-family: 'Font Awesome 6 Free', 'Font Awesome 6 Brands' !important;
}

/* Good line spacing for readability */
.mes_text {
  line-height: 1.55 !important;
}

/* Rounded message bubbles with soft green border */
.mes {
  margin-bottom: 10px !important;
  border-radius: 14px !important;
  border: 1px solid rgba(120, 180, 130, 0.3) !important;
}

/* Soft green glow on focus */
input:focus, textarea:focus {
  box-shadow: 0 0 12px rgba(120, 180, 130, 0.5) !important;
  border-color: rgba(100, 160, 110, 0.6) !important;
}

/* Sage green scrollbar on light background */
::-webkit-scrollbar {
  width: 8px !important;
  background: rgba(250, 255, 250, 0.9) !important;
}
::-webkit-scrollbar-thumb {
  background: rgba(120, 180, 130, 0.4) !important;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(100, 160, 110, 0.6) !important;
}

/* Soft green accent on buttons */
.menu_button:hover, .fa-solid:hover {
  color: rgba(80, 140, 90, 1) !important;
}

/* Reduce animation distractions */
* {
  transition-duration: 0.15s !important;
}
